import json
import traceback
from enum import Enum
from typing import Any
from pydantic import BaseModel, ValidationError, field_validator
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output
from lfx.schema.message import Message


# ── Defina aqui o schema esperado ──────────────────────────────────────────────
class PayloadModel(BaseModel):
    """Ajuste os campos conforme o contrato do seu JSON."""
    name: str
    age: int
    email: str
    @field_validator("age")
    @classmethod
    def age_must_be_positive(cls, v: int) -> int:
        if v <= 0:
            raise ValueError("age deve ser um inteiro positivo")
        return v
    @field_validator("email")
    @classmethod
    def email_must_have_at(cls, v: str) -> str:
        if "@" not in v:
            raise ValueError("email inválido: deve conter '@'")
        return v.lower().strip()


class ValidationOutput(BaseModel):
    success: bool
    data: PayloadModel | None = None
    error: str | None = None
    traceback: str | None = None


# ── Componente ─────────────────────────────────────────────────────────────────
class CustomComponent(Component):
    display_name = "JSON Validator"
    description = (
        "Recebe uma string JSON, faz parse com json.loads e valida "
        "o schema com um BaseModel Pydantic. Retorna os dados validados "
        "ou uma mensagem de erro estruturada."
    )
    documentation: str = "https://docs.langflow.org/components-custom-components"
    icon = "shield-check"
    name = "JsonValidatorComponent"
    inputs = [
        MessageTextInput(
            name="json_string",
            display_name="JSON String",
            info='Cole aqui o JSON a ser validado.',
            # value='{"name": "Ana", "age": 30, "email": "ana@exemplo.com"}',
            tool_mode=True,
        ),
    ]
    outputs = [
        # Output(display_name="Payload", name="payload", method="build_output", group_outputs=True),
        Output(display_name="age", name="age", method="build_age", group_outputs=True),
        Output(display_name="email", name="email", method="build_email", group_outputs=True),
        Output(display_name="name", name="name", method="build_name", group_outputs=True),
        Output(display_name="success", name="success", method="build_success", group_outputs=True),
    ]

    _cache: ValidationOutput | None = None

    def set_attributes(self, parameters: dict) -> None:
        super().set_attributes(parameters)
        self._cache = None


    def validate_json(self) -> ValidationOutput:
        if self._cache is not None:
            return self._cache

        raw: str = self.json_string
        try:
            parsed: Any = json.loads(raw)
        except json.JSONDecodeError as exc:
            self._cache = ValidationOutput(
                success=False,
                error=f"{exc.__class__.__name__}: {exc}",
                traceback=traceback.format_exc()
            )
            self.status = self._cache
            return self._cache

        try:
            model = PayloadModel(**parsed)
        except ValidationError as exc:
            self._cache = ValidationOutput(
                success=False,
                error=str(exc.errors()),
                traceback=traceback.format_exc()
            )
            self.status = self._cache
            return self._cache

        self._cache = ValidationOutput(success=True, data=model)
        self.status = self._cache
        return self._cache

    # def build_output(self) -> Message:
    #     json_validation = self.validate_json()
    #     return Message(text=json_validation.model_dump_json())

    def build_age(self) -> Message:
        payload = self.validate_json()
        if payload.success:
            return Message(text=str(payload.data.age))
        return Message(text="")

    def build_name(self) -> Message:
        payload = self.validate_json()
        if payload.success:
            return Message(text=str(payload.data.name))
        return Message(text="")

    def build_email(self) -> Message:
        payload = self.validate_json()
        if payload.success:
            return Message(text=str(payload.data.email))
        return Message(text="")

    def build_success(self) -> Message:
        result = self.validate_json()
        return Message(text="true" if result.success else "false")

import re

from lfx.custom.custom_component.component import Component
from lfx.io import BoolInput, DropdownInput, IntInput, MessageTextInput, Output
from lfx.schema.message import Message


class ConditionalRouterComponent(Component):
    display_name = "If-Else"
    description = "Routes an input message to a corresponding output based on text comparison."
    documentation: str = "https://docs.langflow.org/if-else"
    icon = "split"
    name = "ConditionalRouter"

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.__iteration_updated = False

    inputs = [
        MessageTextInput(
            name="input_text",
            display_name="Text Input",
            info="The primary text input for the operation.",
            required=True,
        ),
        DropdownInput(
            name="operator",
            display_name="Operator",
            options=[
                "equals", "not equals", "contains",
                "starts with", "ends with", "regex",
                "less than", "less than or equal",
                "greater than", "greater than or equal",
            ],
            value="equals",
            real_time_refresh=True,
        ),
        MessageTextInput(
            name="match_text",
            display_name="Match Text",
            info="The text to compare against.",
            required=True,
        ),
        MessageTextInput(
            name="true_text",
            display_name="Text if True",
            info="The text to output when the condition is True.",
            required=True,
        ),
        MessageTextInput(
            name="false_text",
            display_name="Text if False",
            info="The text to output when the condition is False.",
            required=True,
        ),
        BoolInput(
            name="case_sensitive",
            display_name="Case Sensitive",
            value=True,
            advanced=True,
        ),
        IntInput(
            name="max_iterations",
            display_name="Max Iterations",
            value=10,
            advanced=True,
        ),
        DropdownInput(
            name="default_route",
            display_name="Default Route",
            options=["true_result", "false_result"],
            value="false_result",
            advanced=True,
        ),
    ]

    outputs = [
        Output(display_name="True", name="true_result", method="true_response", group_outputs=True),
        Output(display_name="False", name="false_result", method="false_response", group_outputs=True),
    ]

    def _pre_run_setup(self):
        self.__iteration_updated = False

    def evaluate_condition(self, input_text: str, match_text: str, operator: str, *, case_sensitive: bool) -> bool:
        if not case_sensitive and operator != "regex":
            input_text = input_text.lower()
            match_text = match_text.lower()

        if operator == "equals":
            return input_text == match_text
        if operator == "not equals":
            return input_text != match_text
        if operator == "contains":
            return match_text in input_text
        if operator == "starts with":
            return input_text.startswith(match_text)
        if operator == "ends with":
            return input_text.endswith(match_text)
        if operator == "regex":
            try:
                return bool(re.match(match_text, input_text))
            except re.error:
                return False
        if operator in ["less than", "less than or equal", "greater than", "greater than or equal"]:
            try:
                input_num = float(input_text)
                match_num = float(match_text)
                if operator == "less than":
                    return input_num < match_num
                if operator == "less than or equal":
                    return input_num <= match_num
                if operator == "greater than":
                    return input_num > match_num
                if operator == "greater than or equal":
                    return input_num >= match_num
            except ValueError:
                return False
        return False

    def iterate_and_stop_once(self, route_to_stop: str):
        if not self.__iteration_updated:
            self.update_ctx({f"{self._id}_iteration": self.ctx.get(f"{self._id}_iteration", 0) + 1})
            self.__iteration_updated = True
            current_iteration = self.ctx.get(f"{self._id}_iteration", 0)

            if current_iteration >= self.max_iterations and route_to_stop == self.default_route:
                if self._id in self.graph.conditional_exclusion_sources:
                    previous_exclusions = self.graph.conditional_exclusion_sources[self._id]
                    self.graph.conditionally_excluded_vertices -= previous_exclusions
                    del self.graph.conditional_exclusion_sources[self._id]
                route_to_stop = "true_result" if route_to_stop == "false_result" else "false_result"
                self.stop(route_to_stop)
                return

            self.stop(route_to_stop)
            self.graph.exclude_branch_conditionally(self._id, output_name=route_to_stop)

    def true_response(self) -> Message:
        result = self.evaluate_condition(
            self.input_text, self.match_text, self.operator, case_sensitive=self.case_sensitive
        )
        current_iteration = self.ctx.get(f"{self._id}_iteration", 0)
        force_output = current_iteration >= self.max_iterations and self.default_route == "true_result"

        if result or force_output:
            output = Message(text=self.true_text)
            self.status = output
            if not force_output:
                self.iterate_and_stop_once("false_result")
            return output

        self.iterate_and_stop_once("true_result")
        return Message(text=self.true_text)

    def false_response(self) -> Message:
        result = self.evaluate_condition(
            self.input_text, self.match_text, self.operator, case_sensitive=self.case_sensitive
        )
        current_iteration = self.ctx.get(f"{self._id}_iteration", 0)
        force_output = current_iteration >= self.max_iterations and self.default_route == "false_result"

        if not result or force_output:
            output = Message(text=self.false_text)
            self.status = output
            if not force_output:
                self.iterate_and_stop_once("true_result")
            return output

        self.iterate_and_stop_once("false_result")
        return Message(text=self.false_text)

    def update_build_config(self, build_config: dict, field_value: str, field_name: str | None = None) -> dict:
        if field_name == "operator":
            if field_value == "regex":
                build_config.pop("case_sensitive", None)
            elif "case_sensitive" not in build_config:
                case_sensitive_input = next(
                    (f for f in self.inputs if f.name == "case_sensitive"), None
                )
                if case_sensitive_input:
                    build_config["case_sensitive"] = case_sensitive_input.to_dict()
        return build_config
